        "name": "BOPP Printed Film"
      },
      "priority": "high",
      "status": "in_progress",
      "plannedQty": 1000,
      "myStage": {
        "_id": "665f2b2b3c4d5e6f7a8b9c3a",
        "stage": "printing",
